// Level 2 pool generator — calls https://vocara-peach.vercel.app API endpoints
// Vocab L2 already generated by test call — all endpoints run here for completeness
const BASE = 'https://vocara-peach.vercel.app'
const TIMEOUT_MS = 180000 // 3 min per call

const delay = ms => new Promise(r => setTimeout(r, ms))

async function call(label, path, body) {
  process.stdout.write(`  ▶ ${label}… `)
  try {
    const ctrl = new AbortController()
    const tid = setTimeout(() => ctrl.abort(), TIMEOUT_MS)
    const res = await fetch(`${BASE}${path}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
      signal: ctrl.signal,
    })
    clearTimeout(tid)
    const data = await res.json()
    if (!res.ok) {
      console.log(`✕ HTTP ${res.status}: ${JSON.stringify(data).slice(0, 100)}`)
      return { ok: false, status: res.status }
    }
    const summary = data.results
      ? data.results.map(r => `${r.langPair || ''} L${r.level || ''}: ${r.count ?? r.error ?? '?'}`).join(' | ')
      : data.generated
        ? data.generated.map(r => `${r.pair}: ${r.count ?? r.total ?? r.error ?? '?'}`).join(' | ')
        : JSON.stringify(data).slice(0, 100)
    console.log(`✓ ${summary}`)
    return { ok: true, summary }
  } catch (e) {
    console.log(`✕ ${e.name === 'AbortError' ? 'TIMEOUT' : e.message}`)
    return { ok: false, error: e.message }
  }
}

const JOBS = [
  // Base / Grundlagen — per pair
  { label: 'Base Grundlagen L2 de→en', path: '/api/generate-base-pool',              body: { level: 2, from: 'de', to: 'en' } },
  { label: 'Base Grundlagen L2 en→de', path: '/api/generate-base-pool',              body: { level: 2, from: 'en', to: 'de' } },
  { label: 'Base Grundlagen L2 de→sw', path: '/api/generate-base-pool',              body: { level: 2, from: 'de', to: 'sw' } },
  // Vocab — all pairs (already ran in test, re-running to confirm)
  { label: 'Vocab L2 (all pairs)',      path: '/api/generate-vocab-pool',             body: { level: 2 } },
  // Street
  { label: 'Street L2 (all pairs)',     path: '/api/generate-street-pool',            body: { level: 2 } },
  // Home
  { label: 'Home L2 (all pairs)',       path: '/api/generate-home-pool',              body: { level: 2 } },
  // Sentence flashcards
  { label: 'Sentence FC L2 (all pairs)',path: '/api/generate-sentence-pool',         body: { type: 'flashcards', level: 2 } },
  // Sentence training exercises
  { label: 'Satz Training L2 (all pairs)', path: '/api/generate-sentence-training-pool', body: { level: 2 } },
]

async function main() {
  console.log(`\n▶ Level 2 pool generation via ${BASE} — ${JOBS.length} jobs\n`)
  const results = []
  for (const { label, path, body } of JOBS) {
    const r = await call(label, path, body)
    results.push({ label, ...r })
    if (JOBS.indexOf(JOBS.find(j => j.label === label)) < JOBS.length - 1) await delay(2000)
  }
  console.log('\n── Summary ──────────────────────────────────────────')
  results.forEach(r => {
    const icon = r.ok ? '✓' : '✕'
    const detail = r.ok ? r.summary : (r.error || `HTTP ${r.status}`)
    console.log(`  ${icon} ${r.label} → ${detail}`)
  })
  const ok = results.filter(r => r.ok).length
  console.log(`\n  ${ok}/${results.length} succeeded\n`)
}

main().catch(e => { console.error('Fatal:', e); process.exit(1) })
